function formatTime(t,o){var o=Math.floor(t%1*(o||0)),t=Math.floor(t),r=Math.floor(t/60),a=Math.floor(r/60),e=t=>{var o=t.toString();return t<10?t<=0?"00":"0"+o:o};return r%=60,t%=60,(0<a?e(a)+":":"")+e(r)+":"+e(t)+(o?":"+e(o):"")}function timeToSeconds(t){t=t.replace(/;/g,":").split(":");let o=0;return o=3===t.length?(o=(o+=60*parseFloat(t[0])*60)+60*parseFloat(t[1]))+parseFloat(t[2]):(o+=60*parseFloat(t[0]))+parseFloat(t[1])}export{formatTime,timeToSeconds};